class Solution(object):
    def minTime(self, s, order, k):
        n = len(s)
        total = n * (n + 1) // 2
        if total < k:
            return -1

        def count_valid(t):
            starred = set(order[:t + 1])
            invalid = 0
            run = 0
            for i in range(n):
                if i in starred:
                    invalid += run * (run + 1) // 2
                    run = 0
                else:
                    run += 1
            invalid += run * (run + 1) // 2
            return total - invalid

        lo, hi = 0, n - 1
        ans = -1
        while lo <= hi:
            mid = (lo + hi) // 2
            if count_valid(mid) >= k:
                ans = mid
                hi = mid - 1
            else:
                lo = mid + 1
        return ans
